// ─── Helper para carregar do localStorage com fallback ───────────────────────
// ─── Versão dos dados — incremente quando mudar dados iniciais ───────────────
const DATA_VERSION = '2025-05-15-v4';

function loadFromStorage(key, fallback) {
  try {
    // Se a versão dos dados mudou, descarta o cache e usa os dados iniciais
    const storedVersion = localStorage.getItem('biscoite_data_version');
    if (storedVersion !== DATA_VERSION) {
      // Limpa tudo e marca nova versão
      Object.keys(localStorage)
        .filter(k => k.startsWith('biscoite_'))
        .forEach(k => localStorage.removeItem(k));
      localStorage.setItem('biscoite_data_version', DATA_VERSION);
      return fallback;
    }
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : fallback;
  } catch {
    return fallback;
  }
}

// Garante que itens novos do INITIAL_MENU_ITEMS sejam adicionados
// mesmo que o usuário já tenha dados antigos no localStorage
function loadMenuItems() {
  const saved = loadFromStorage('biscoite_menu_items', INITIAL_MENU_ITEMS);
  const savedIds = new Set(saved.map(i => i.id));
  const missing = INITIAL_MENU_ITEMS.filter(i => !savedIds.has(i.id));
  return missing.length > 0 ? [...saved, ...missing] : saved;
}

// ─── Helper de sanitização ───────────────────────────────────────────────────
export function sanitizeText(str, maxLen = 200) {
  return String(str ?? '').trim().slice(0, maxLen);
}

