        ...c,
        messages: [...c.messages, msg],
        lastMsg: text,
        lastTime: 'agora',
        unreadProf: from === 'user' ? c.unreadProf + 1 : c.unreadProf,
        unreadUser: from === 'prof' ? c.unreadUser + 1 : c.unreadUser,
